"""
MKT Christ Commentary — 1 Kings chapters 3–5
Run: python3 scripts/zc-christ-1kings-3-5.py

Source data used:
- data/interlinear/1kings.json
- data/translation/draft/mediating/1kings.json (MKT text)
- data/commentary/mkt-christ/1kings.json (existing entries for continuity)

Key decisions in this range:
- Ch 3: Solomon as type of Christ the Wise King; the Gibeon dream as revelation of God's gracious initiative;
  the judgment scene (vv16-27) as shadow of Christ's wisdom that cannot be deceived.
- Ch 4: Administrative lists treated briefly; vv20-21 (Abrahamic fulfillment and universal dominion) and
  vv29-34 (surpassing wisdom) receive fuller treatment as Christological peaks.
- Ch 5: Temple preparations; "rest" language in vv3-4 as anticipation of Hebrews 4; temple construction
  project as type of Christ's body (John 2:19-21).
- Solomon throughout: shadow/type of the greater Son of David (Matt 12:42; 1 Cor 1:24).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS1 = {
  "3": {
    "1": "<p>A shadow: Solomon's marriage alliance with Pharaoh king of Egypt violates the Deuteronomic prohibition (Deut 17:17; cf. Neh 13:26) and foreshadows the spiritual compromise that will end his reign. That he brings Pharaoh's daughter into the city of David — the holy city — signals the entanglement of covenant kingship with foreign power. The greater Son of David will not compromise covenant loyalty; he comes not to make treaties with the powers of this age but to defeat them (Col 2:15).</p>",
    "2": "<p>A theme: the absence of a house for YHWH's name explains why the people still sacrificed at the high places. The longing for the temple runs through 1-2 Kings as a longing for the proper dwelling of God among his people. The NT presents Christ as the true fulfillment of that longing: 'in him the whole fullness of deity dwells bodily' (Col 2:9) and 'the Word tabernacled among us' (John 1:14). Every high-place substitute for genuine divine presence anticipates the NT's verdict that only in Christ is the presence of God with his people made full and permanent.</p>",
    "3": "<p>A revelation of God: Solomon's love for YHWH and his walk in his father David's statutes establishes the standard by which his later apostasy will be measured. The qualification — 'except that he offered sacrifices at the high places' — is the seed of future failure. The NT uses this trajectory to illustrate that partial obedience is not covenant faithfulness; the law requires perfect obedience (Gal 3:10), which only Christ fulfills on behalf of his people (Rom 8:3-4).</p>",
    "4": "<p>A theme: Solomon's thousand burnt offerings at Gibeon represent extravagant piety, a devotion that YHWH honors with the dream theophany. The 'most prominent high place' will soon be superseded by the Jerusalem temple, just as every earthly structure for worship is superseded by Christ himself as the meeting place of God and humanity (John 4:21-24; Heb 9:11-12). Lavish worship offered in good faith toward YHWH is the correct instinct; Christ fulfills and redirects it to himself.</p>",
    "5": "<p>A revelation of God: the Gibeon dream — 'Ask whatever you wish and I will give you' — is one of the OT's clearest pictures of divine grace reaching toward the king before he has done anything. God approaches Solomon; God initiates the gift. The NT makes this structure explicit in Christ: 'You did not choose me, but I chose you' (John 15:16); 'while we were still sinners, Christ died for us' (Rom 5:8). God's gracious approach to Solomon in a dream is a shadow of the incarnation itself — God coming near to his people with an open hand.</p>",
    "6": "<p>A theme: Solomon appeals to YHWH's steadfast love (<em>hesed</em>) toward David — the covenant-loyalty that is the ground of all the blessings he is about to receive. This covenant structure anticipates the NT's argument in Romans: the blessings of salvation come not through individual merit but through God's covenant faithfulness, now revealed through Christ who is the 'yes' to all God's promises (2 Cor 1:20). Solomon stands in the stream of grace flowing to him because of his father; believers stand in the stream of grace flowing to them because of Christ.</p>",
    "7": "<p>A theme: Solomon's confession of inadequacy — 'I am only a young man; I do not know how to go out or come in' — is the posture that makes him capable of asking for wisdom rather than power. The NT presents Christ as the one who, though equal with God, 'did not count equality with God a thing to be grasped' but emptied himself (Phil 2:6-7). Solomon's humility is a shadow; Christ's kenosis is the reality. Both receive divine exaltation as a result (1 Kgs 3:13; Phil 2:9-11).</p>",
    "8": "<p>A theme: 'Your servant stands in the midst of your chosen people, a great people too numerous to be counted.' The Abrahamic promise of a people as numerous as the sand (Gen 22:17) is already partially realized in Solomon's Israel. The greater fulfillment is the church drawn from all nations: 'a great multitude that no one could count, from every nation, tribe, people and language' (Rev 7:9). Solomon's awe at the size of the people he is called to lead points toward the scope of Christ's kingdom that no earthly monarch can contain.</p>",
    "9": "<p>A type: Solomon's request for 'an understanding mind to govern your people, that I may discern between good and evil' is a request for wisdom rather than power. Jesus identifies himself with this exact theme: 'something greater than Solomon is here' (Matt 12:42). Paul identifies Christ as 'the wisdom of God' (1 Cor 1:24) and says that 'in him are hidden all the treasures of wisdom and knowledge' (Col 2:3). Solomon's request is the OT's most explicit royal petition for wisdom; Christ is its fulfillment. What Solomon asked for, Christ is — not as a gift received but as the eternal nature of the Son of God.</p>",
    "10": "<p>A revelation of God: 'It pleased the Lord that Solomon had asked for this.' YHWH's delight in Solomon's request rather than requests for wealth, power, or vengeance reveals God's own priorities: wisdom and justice for the people over personal advancement. This delight anticipates the Father's words at Jesus's baptism — 'This is my beloved Son, in whom I am well pleased' (Matt 3:17) — spoken not after a list of royal achievements but after an act of covenant identification (baptism with sinners). The Father delights in the Son who comes not to be served but to serve (Matt 20:28).</p>",
    "11": "<p>A revelation of God: God's comparison of Solomon's request with possible requests for long life, riches, or enemies' deaths reveals the theological hierarchy of values in the covenant: justice for the people ranks above personal benefit. This hierarchy is embodied in Christ, who 'did not please himself' (Rom 15:3) and gave himself for others rather than seeking his own preservation. God's response to Solomon reveals that the king who forgets himself in service to others is the king who most fully reflects God's own character.</p>",
    "12": "<p>A type: 'I give you a wise and discerning mind, so that no one like you has existed before and no one like you will arise after you.' This superlative — unprecedented wisdom — is immediately relativized by Jesus's 'something greater than Solomon is here' (Matt 12:42). Solomon's incomparable wisdom is real but partial; it is human wisdom supernaturally gifted. Christ's wisdom is divine wisdom incarnate. The NT contrast is not Solomon versus nothing, but Solomon's shadow versus Christ's reality (Col 2:17).</p>",
    "13": "<p>A theme: 'I also give you what you did not ask for — both wealth and honor.' The principle that seeking first the kingdom produces additional gifts appears in its seed form here: Solomon sought wisdom for the people's sake and received wisdom plus all the goods he did not seek. Jesus teaches the same structure: 'Seek first the kingdom of God and his righteousness, and all these things will be added to you' (Matt 6:33). The Solomonic narrative is the narrative example of the teaching Jesus will give.</p>",
    "14": "<p>A theme: 'And if you walk in my ways... I will give you long life.' The conditional promise of long life for covenant obedience is the Deuteronomic framework throughout 1 Kings. Solomon does not ultimately walk in YHWH's ways, and dies; but Christ walks in perfect covenant obedience and dies anyway — bearing the curse of others' disobedience (Gal 3:13). In Christ, the conditionality is resolved: he fulfilled the condition perfectly, so the blessing flows to all who are in him, not on the basis of their own walk but his.</p>",
    "15": "<p>A theme: Solomon awakes and stands before the ark of the covenant, offering burnt offerings and peace offerings. The ark — the seat of YHWH's presence between the cherubim — is the OT meeting point between God and his people. Solomon's instinct after the divine encounter is to return to the place of divine presence. The ark's role as the earthly localization of YHWH's presence gives way, in the NT, to the ascended Christ who is the presence of God at the Father's right hand (Heb 9:24), our advocate and high priest before the Father.</p>",
    "16": "<p>A theme: the transition from the dream theophany to a realistic legal dispute — two prostitutes and a dead child — is striking. The wisdom God gives Solomon is not otherworldly but practical: it operates in the messiest human situations. Christ's wisdom similarly engages the actual messy world: tax collectors, adulterous women, lepers, demon-possessed men. The 'wisdom from above' (Jas 3:17) is not speculative but ethical and judicial, operating precisely where human judgment fails.</p>",
    "17": "<p>A theme: the first woman's claim and the narrative of the overlapping births establishes the legal impossibility of the case: there are no witnesses, and both mothers claim the living child. This is the kind of judicial impasse that cannot be resolved by normal evidence — only by wisdom that can read what witnesses cannot see. Christ's wisdom similarly penetrates to the heart: 'he knew what was in man' (John 2:25) and answers questions from the heart's motive rather than its surface claim (Matt 22:15-22).</p>",
    "18": "<p>A theme: 'We were alone — there was no one else with us in the house.' The absence of witnesses is the theological problem: justice normally depends on testimony. The Mosaic law requires two or three witnesses (Deut 17:6). Solomon's wisdom will provide what witnesses cannot. The NT parallel is Christ's authority to judge without the normal evidential requirement: 'He who sent me is with me ... and I judge truly' (John 8:16). Divine wisdom supplements human evidence.</p>",
    "19": "<p>A theme: the woman's dead son and her midnight substitution with the living child sets up the central question of the narrative: which child is alive? The life-death contrast in this story resonates with the NT's central theme: the death of one (the child overlaid) and the life of another, with a mother's anguish at the center. That the true mother prefers her child live with another rather than die is a shadow of Christ's willingness to give his life rather than see others perish (John 3:16).</p>",
    "20": "<p>A theme: 'She placed her dead son at my breast and took my living child.' The substitution — a dead child for a living one — echoes the structure of substitutionary sacrifice without being a type: here the substitution is criminal. But it frames the question that drives the narrative: whose child is the living one? In the gospel, Christ takes the death of sinners (substitution) so that the living Child — the Son — might be known as theirs by adoption (Rom 8:15-17). The motif of life-death substitution pervades both stories.</p>",
    "21": "<p>A theme: the mother's careful morning examination of the child — 'it was not the son I bore' — is the moment of recognition that drives her to the king. Only the king can render justice when human examination has reached its limit. This reaches toward Christ as the final judge to whom the wronged bring their case; the NT presents Christ as the one who 'will bring to light the things now hidden in darkness and will disclose the purposes of the heart' (1 Cor 4:5).</p>",
    "22": "<p>A theme: the two women's contradictory claims before the king — each insisting the living child is hers — produce a legal deadlock that normal judicial procedure cannot resolve. Solomon's genius is to create a situation where the true mother's love will betray her. Christ's wisdom similarly reframes impossible situations: when Pharisees try to trap him between Rome and God (Matt 22:15-22), his answer bypasses the trap entirely and answers at a deeper level.</p>",
    "23": "<p>A theme: Solomon restates the dispute with precision: two claims, each the mirror image of the other. The king's clarity about the structure of the problem is the first move in resolving it. Wisdom is first diagnostic before it is prescriptive. Christ's wisdom similarly diagnoses before prescribing: he names the real question behind the surface question in every controversy, exposing what his opponents are actually asking (Mark 12:13-17).</p>",
    "24": "<p>A theme: 'Bring me a sword.' The sword command is deliberately ambiguous — it could be the king enacting an atrocity or revealing the truth. It is wisdom's instrument of discernment: the order that only the true mother cannot accept. Christ uses similarly arresting, even shocking language to surface the real position of hearts: 'Do you think I have come to bring peace on earth? No, but rather division' (Luke 12:51). Wisdom sometimes shocks in order to reveal.</p>",
    "25": "<p>A shadow: 'Cut the living child in two.' The impossible command — which would destroy what both women claim to want — is designed to produce the response of authentic love. No true mother would accept half a living child over a whole dead one. This shadow points toward Gethsemane: Christ does not divide himself, does not offer half — he gives the whole of himself (John 10:11, 17-18). The sword judgment is the crucible that reveals who truly loves and who only claims to.</p>",
    "26": "<p>A type: 'The woman whose son was alive cried out to the king — her heart ached for her son — Please, my lord, give her the living child, and do not kill him.' The true mother's love is revealed precisely when she surrenders her claim rather than see the child die. This is the shape of genuine love in the biblical narrative: Abraham willing to give up Isaac (Gen 22:12), the father running to the prodigal (Luke 15:20), Christ giving his life for others (John 15:13). Love that would rather let go than see the beloved destroyed is the NT's definition of agape.</p>",
    "27": "<p>A type: 'Give the living child to the first woman, and do not kill him. She is his mother.' Solomon's verdict returns the child to his true mother through wisdom that sees what no witness saw. A type of Christ's wisdom: the one who truly belongs to Christ is returned to him not through human force but through a wisdom that reads the heart. The NT's application is the image of Christ knowing his own: 'My sheep hear my voice, and I know them' (John 10:27). The judge who can see through pretense and return the living to their true owner is the shadow; Christ is the substance.</p>",
    "28": "<p>A shadow: all Israel heard the judgment and stood in awe of Solomon, because they saw that God's wisdom was in him. The awe of the people at Solomon's wisdom is the shadow of the awe at Christ's wisdom: the crowds 'were astonished at his teaching, for he taught them as one who had authority' (Matt 7:28-29). What Israel glimpses in Solomon's judgment — divine wisdom operating through a human king — is the reality in Christ, who is not merely an instrument of divine wisdom but is wisdom itself (1 Cor 1:24, 30).</p>"
  },
  "4": {
    "1": "<p>A theme: 'King Solomon was king over all Israel.' The full sovereignty of Solomon over all twelve tribes marks the fulfillment of the united monarchy that David established. This united kingdom under a single wise king is the OT's clearest picture of the coming kingdom of the Son of David, who will reign over all God's people — the new Israel gathered from every nation (Eph 1:10; Rev 11:15). The administrative chapters that follow describe the machinery of this reign: Christ's reign will transcend all such machinery but fulfills what it dimly pictures.</p>",
    "2": "<p>A theme: Azariah son of Zadok as priest — the priest-king dynamic that Solomon embodies (the king who offers sacrifices and tends the temple) finds its fulfillment in Christ as both King and High Priest after the order of Melchizedek (Heb 7:1-3), the priest-king of Salem who preceded both Levi and David. Solomon's court structure, with a priest as chief official, shadows the eschatological order where priesthood and kingship are united in the one mediator (1 Tim 2:5).</p>",
    "3": "<p>A theme: the secretary-recorders of Solomon's court record the words and acts of the king. The NT's evangelists perform the same function for the greater King: 'These are written so that you may believe that Jesus is the Christ, the Son of God' (John 20:31). The administrative scribal apparatus of the Solomonic court points toward the written record through which Christ's reign is announced and the covenant documented — the New Testament itself as the record of the greater King's words and acts.</p>",
    "4": "<p>A theme: Benaiah over the army, Zadok and Abiathar as priests — the separation of military and priestly functions in Solomon's administration reflects the covenant order in which different offices serve different ends. Christ unites in himself what these officers hold separately: he is Prophet (the word of God), Priest (atonement and intercession), and King (ruler over all). The distributed offices of Solomon's court are shadows of the threefold office unified in Christ.</p>",
    "5": "<p>A theme: Zabud son of Nathan was 'the king's personal friend.' The king's friend (Hebrew <em>re'eh ha-melek</em>) is an honorific title for the most intimate counselor. Jesus calls his disciples 'friends' rather than servants: 'No longer do I call you servants... but I have called you friends, for all that I have heard from my Father I have made known to you' (John 15:15). What the king's personal friend holds in Solomon's court — access to the king's counsel and intimate knowledge of his purpose — is what Christ gives to all his disciples.</p>",
    "6": "<p>A theme: Adoniram over the forced labor — the darker element of Solomon's kingdom. The corvée labor will become the flashpoint for the kingdom's division (1 Kgs 12:4). Even Solomon's magnificent building program rests on coerced labor, a shadow side of the Solomonic ideal. Christ's kingdom reverses this: he does not conscript workers but calls them, and calls them to a 'yoke that is easy and a burden that is light' (Matt 11:30). The greater Son of David liberates rather than conscripts.</p>",
    "7": "<p>A theme: twelve district governors for all Israel — Solomon reorganizes the tribal territories into administrative districts for provisioning the royal household. The number twelve echoes the twelve tribes and, in the NT, the twelve apostles who will administer the new covenant people (Matt 19:28; Rev 21:12-14). The Solomonic administrative structure is the OT scaffold; the apostolic structure is its NT fulfillment — twelve over Israel, twelve over the new Israel.</p>",
    "8": "<p>A theme: Ben-hur in the hill country of Ephraim. The administrative list of district governors (vv8-19) demonstrates the extent and organization of Solomon's kingdom. These lists, though seemingly dull, record the concrete reality of covenant promise fulfilled: YHWH promised Abraham the land, and under Solomon the land is organized, provisioned, and governed. Christ's kingdom will similarly be concrete and organized — 'the kingdoms of this world have become the kingdom of our Lord and of his Christ' (Rev 11:15), real governance, not merely spiritual sentiment.</p>",
    "9": "<p>A theme: Ben-deker in Makaz, Shaalbim, Beth-shemesh, and Elon-beth-hanan — specific named territories within the covenant land. The specificity signals the fulfillment of the land promise: every corner of Canaan is now under the king's provision and oversight. The NT's fulfillment is universal rather than geographic — Christ's reign extends over every domain of reality (Matt 28:18), and its 'land' is the renewed creation (Rev 21:1).</p>",
    "10": "<p>A theme: Ben-hesed in Arubboth — the name <em>hesed</em> ('steadfast love, covenant loyalty') embedded in an administrative official's name is a small signal that the covenant vocabulary of Israel's God saturates even the bureaucratic structure of the kingdom. God's own character (<em>hesed</em>) is written into the names and titles of the king's servants. Christ's kingdom will be the full embodiment of this: 'God is love' (1 John 4:8) expressed through every member of the new covenant community.</p>",
    "11": "<p>A theme: Ben-abinadab, who had Solomon's daughter Taphath as his wife — the integration of the administrative officers into the royal family through marriage signals the consolidation of power through covenant relationship. The NT's image of the church as 'the bride of Christ' (Rev 21:2; Eph 5:25-27) is the eschatological fulfillment of this pattern: union with the king through covenant relationship, not merely bureaucratic appointment.</p>",
    "12": "<p>A theme: Baana in Taanach and Megiddo — historic battlegrounds of Israel's history (Deborah and Barak fought at Megiddo, Judg 5:19; the valley of Megiddo is the site of Revelation's final battle, Rev 16:16). Solomon's governor now provides food from these sites of past conflict. What was a battlefield is now a breadbasket — the peace of Solomon's reign transforming old conflict zones into productive territory. A shadow of the eschatological peace when Christ makes all things new (Rev 21:5).</p>",
    "13": "<p>A theme: Ben-geber in Ramoth-gilead, including the villages of Jair son of Manasseh and the region of Argob with sixty large fortified cities. The administration extends to the Transjordan territories captured under Moses. The covenant land — including the less-celebrated Transjordan territories — is fully incorporated under Solomon's governance. Christ's kingdom similarly includes those on the margins: the Gentiles, the distant nations, all who are 'outside' by natural covenant status (Eph 2:11-13).</p>",
    "14": "<p>A theme: Ahinadab in Mahanaim — Mahanaim was the site where Jacob encountered the angels of God (Gen 32:1-2) and where David fled from Absalom (2 Sam 17:24). Now a food district for Solomon's table. Places of theophany and crisis become ordinary administrative territories; what was extraordinary covenant moment becomes the background of a stable kingdom. The NT makes this point eschatologically: the extraordinary moments of divine encounter — incarnation, resurrection — become the ordinary background of the new creation order.</p>",
    "15": "<p>A theme: Ahimaaz in Naphtali — Naphtali, the tribal territory Jesus would later inhabit: 'The land of Zebulun and the land of Naphtali ... and for those dwelling in the region and shadow of death, a light has dawned' (Matt 4:15-16, quoting Isa 9:1-2). What is a food-production district in Solomon's kingdom becomes the site of the dawning of gospel light in the NT. The administrative geography of the Solomonic kingdom is the map on which Christ's ministry will be enacted.</p>",
    "16": "<p>A theme: Baanah in Asher and Bealoth. Asher was promised blessing and the favor of his brothers with his feet dipped in oil (Deut 33:24), and Anna the prophetess who recognized the infant Jesus at the temple was from the tribe of Asher (Luke 2:36). The Asherite presence in Solomon's administration and in the temple at Christ's presentation is the same tribal thread running from Moses's blessing through the Solomonic kingdom to the moment of recognition at Christ's coming.</p>",
    "17": "<p>A theme: Jehoshaphat in Issachar. The name Jehoshaphat means 'YHWH has judged' — an official whose name announces divine justice over the territory he administers. The Solomonic kingdom embeds covenant theology into its administrative vocabulary. The NT's proclamation is that YHWH has judged in Christ: 'the Father judges no one, but has given all judgment to the Son' (John 5:22). What the name proclaims, Christ performs.</p>",
    "18": "<p>A theme: Shimei in Benjamin. Benjamin — the smallest tribe (1 Sam 9:21), from whom Saul came — is administered under Solomon the Judahite king. The inclusion of Benjamin under David's and Solomon's line represents the integration of all Israel under the covenant king. Paul was 'a Hebrew of Hebrews, of the tribe of Benjamin' (Phil 3:5) who would serve the greater Son of David; the Benjaminite tradition is incorporated, not discarded, in the new covenant.</p>",
    "19": "<p>A theme: Geber in Gilead, the territory of Sihon and Og — the two Transjordan kings defeated by Moses (Num 21:21-35; Deut 2-3) whose territory became Israel's by conquest. Solomon's administrative reach extends to the furthest edges of the Mosaic conquest. Christ's commission extends beyond all geographic limits: 'all authority in heaven and on earth has been given to me. Go therefore and make disciples of all nations' (Matt 28:18-19). The Solomonic border is the OT figure; the universal commission is the NT fulfillment.</p>",
    "20": "<p>A direct fulfillment: 'Judah and Israel were as numerous as the sand by the sea. They ate and drank and were content.' The Abrahamic promise — 'your offspring will be as the sand of the sea' (Gen 22:17) — reaches its OT fulfillment in Solomon's Israel. Paul sees the deeper fulfillment: the promise to Abraham's 'offspring' is fulfilled in Christ, 'who is one' (Gal 3:16), and through Christ extends to all who are in him — 'as many as the sand on the seashore' drawn from every nation (Rev 20:8 uses this phrase for the nations coming to Christ). Solomon's Israel is the OT chapter; the church is the NT chapter of the same promise.</p>",
    "21": "<p>A shadow: 'Solomon ruled over all the kingdoms from the Euphrates to the land of the Philistines and as far as the border of Egypt.' This is the covenant land at its maximal extent — the boundaries promised to Abraham (Gen 15:18) and partially realized under David, now fully realized under Solomon. The geographic reach of Solomon's kingdom is the OT's most explicit fulfillment of the land promise. The NT transcends geography: Christ's dominion extends over 'all authority in heaven and on earth' (Matt 28:18) and over 'every tribe and language and people and nation' (Rev 5:9). The Solomonic land promise points toward the eschatological new earth (Rev 21).</p>",
    "22": "<p>A theme: the provisioning of Solomon's household — 'thirty cors of fine flour and sixty cors of ordinary flour' — is a daily demonstration of YHWH's faithfulness to provide for the king and his people. The daily provision theme is embedded in the Lord's Prayer ('give us this day our daily bread,' Matt 6:11) and in the manna narratives (Exod 16:4). Christ himself is the living bread from heaven (John 6:35) — the antitype of all the daily bread that sustained Israel and their king.</p>",
    "23": "<p>A theme: fattened oxen, pasture-fed cattle, sheep, deer, gazelles, roebucks, and choice fowl — the lavish daily provision for Solomon's table echoes the eschatological feast imagery. Isaiah's mountain feast (Isa 25:6) and the NT's wedding supper of the Lamb (Rev 19:9) project this Solomonic abundance into eternity. Solomon's table is a shadow of the final feast when all God's people will eat and be content in the presence of the greater King.</p>",
    "24": "<p>A shadow: Solomon's dominion over all the region west of the Euphrates, from Tiphsah to Gaza, with all the kings submitting to him and paying tribute. The vision of earthly kings submitting to the covenant king is a shadow of Psalm 72 (which imagines the ideal king to whom all kings bow) and of Revelation 21:24 (the kings of the earth bringing their glory into the new Jerusalem). Solomon's political hegemony is a temporal, imperfect anticipation of Christ's eschatological sovereignty.</p>",
    "25": "<p>A shadow: 'During Solomon's lifetime Judah and Israel lived in safety, from Dan to Beersheba, each man under his own vine and his own fig tree.' The vine-and-fig-tree image is the OT's primary picture of covenant peace — every person secure in their inherited portion (Mic 4:4; Zech 3:10). Nathanael's experience under the fig tree when Jesus calls him (John 1:48-50) activates this imagery: Christ's recognition of him 'before Philip called you' signals the dawning of the vine-and-fig-tree peace in the person of Jesus. Solomon's era of peace is the OT's most complete enactment of this peace; Christ is its eschatological fulfillment.</p>",
    "26": "<p>A shadow: forty thousand stalls for chariot horses and twelve thousand horsemen — the scale of Solomon's military establishment begins to approach the Deuteronomic limit (Deut 17:16: 'he must not acquire many horses for himself'). What begins as shadow will become violation; Solomon's wisdom does not prevent his later multiplication of horses, wives, and silver (1 Kgs 10:26; 11:1-3). The greater Son of David enters Jerusalem 'humble and mounted on a donkey' (Zech 9:9; Matt 21:5) — deliberately refusing the horse-and-chariot power that Solomon accumulates.</p>",
    "27": "<p>A theme: each district governor supplied provisions in his designated month — the orderly, reliable, comprehensive provision for the royal court. The structure of the kingdom's provision reflects the theological principle that the king's household is sustained by the whole land's labor, coordinated and directed by the king's authority. Christ's body — the church — sustains itself through the gifts distributed among all the members (1 Cor 12:4-7), each contributing according to the Spirit's allocation, the whole providing for the whole.</p>",
    "28": "<p>A theme: barley and straw delivered to the horses and swift steeds wherever needed — even the logistical details of Solomon's court are attended to without lack. The completeness of Solomon's provision is a shadow of Christ's promise: 'my God will supply every need of yours according to his riches in glory in Christ Jesus' (Phil 4:19). What is true of Solomon's well-supplied court is true in its fullness of every need in Christ.</p>",
    "29": "<p>A shadow: 'God gave Solomon wisdom and understanding beyond all measure, and a breadth of insight like the sand on the seashore.' Solomon's unsurpassable wisdom is the OT's highest wisdom-claim — and it is exactly what Jesus surpasses (Matt 12:42). The 'sand on the seashore' image for wisdom's breadth echoes the same image for Abraham's offspring (Gen 22:17; 1 Kgs 4:20) — wisdom and covenant people share the same metaphor, suggesting that genuine wisdom and covenant membership are theologically linked. In Christ, wisdom and covenant people coincide: 'he is the source of your life in Christ Jesus, who became to us wisdom from God' (1 Cor 1:30).</p>",
    "30": "<p>A shadow: Solomon's wisdom exceeded 'all the sages of the east and all the wisdom of Egypt.' Egypt's wisdom traditions and Mesopotamian wisdom literature are the cultural competitors; Israel's king surpasses them all. Yet this is still a comparison within human (even if divinely gifted) categories. Christ's wisdom is not 'greater than' the wisdom of the east in the same comparative sense — it is wisdom of a categorically different kind: 'the wisdom of God in a mystery, hidden, which God decreed before the ages for our glory' (1 Cor 2:7). Solomon's wisdom defeats all human rivals; Christ's wisdom makes the whole category obsolete.</p>",
    "31": "<p>A shadow: 'He was wiser than all other men — wiser than Ethan the Ezrahite, and Heman, Chalcol, and Darda, sons of Mahol.' Ethan the Ezrahite is credited with Psalm 89, which prays for the Davidic covenant's fulfillment despite the apparent collapse of the monarchy. Solomon's surpassing of Ethan-the-psalmist in wisdom is ironic: the wisdom of the king will fail, but Ethan's psalm will be answered in the resurrection of Christ (Ps 89:26-29; Acts 2:30-31). Solomon surpasses Ethan in life; Ethan's hope surpasses Solomon's achievement in history.</p>",
    "32": "<p>A shadow: 'He composed three thousand proverbs, and his songs numbered one thousand and five.' Solomon's literary output is staggering — the OT credits him with Proverbs, Ecclesiastes, Song of Songs, and two Psalms (72, 127). But Jesus 'never wrote a book' (as has been noted); his wisdom was enacted and spoken, embodied and relational rather than literary. The greater Wisdom does not produce a library but lives a life, and the record of that life is itself the wisdom literature of the new covenant — the Gospels as the acts of Wisdom incarnate.</p>",
    "33": "<p>A shadow: Solomon spoke about plant life from cedar to hyssop, about animals, birds, reptiles, and fish. His encyclopedic natural wisdom is the OT's vision of the king who understands creation in its totality. Christ demonstrates dominion over creation in ways Solomon only described: calming the sea (Mark 4:39), multiplying fish and bread (John 6:11), cursing the fig tree (Matt 21:19), healing diseased bodies. Solomon spoke about creation; Christ rules it. The encyclopedia of natural wisdom becomes the dominion of the new Adam (1 Cor 15:45-47).</p>",
    "34": "<p>A shadow: 'People from all nations came to hear the wisdom of Solomon, sent by all the kings of the earth who had heard of his fame.' The nations coming to Solomon is the OT's most complete fulfillment of the Abrahamic promise that 'all the nations of the earth shall be blessed' through Abraham's offspring (Gen 22:18). The Queen of Sheba (1 Kgs 10) is the most famous instance. Jesus points to the Queen of the South as the one who will condemn Jesus's generation: she came from the ends of the earth to hear Solomon's wisdom; 'something greater than Solomon is here' (Matt 12:42). The nations came to Solomon; in Christ, the nations are commanded to go and make disciples of all nations (Matt 28:19). The movement is reversed: not nations coming to a center, but the gospel going to every nation.</p>"
  },
  "5": {
    "1": "<p>A theme: Hiram king of Tyre, a Gentile ruler, immediately recognizes Solomon's anointing and sends servants to honor him. A Gentile king's response to the anointed Davidic king anticipates the Gentile recognition of Christ: the magi from the east (Matt 2:1-2), the Roman centurion ('truly this man was the Son of God,' Mark 15:39), and ultimately the nations' incorporation into the covenant people. The Gentile recognition of God's anointed is a recurrent pattern that Christ fulfills universally.</p>",
    "2": "<p>A theme: Solomon's message to Hiram begins with a statement of purpose — to build the temple. The communication of kingdom purpose to a Gentile ally is the OT analog of the NT's proclamation of the gospel to the nations: what God is doing in and through his anointed king is announced publicly, and Gentile cooperation is invited. The church's mission, like Solomon's letter to Hiram, announces what God is building and invites the nations to participate.</p>",
    "3": "<p>A shadow: 'My father David could not build a house for the name of the LORD his God because of the wars surrounding him on every side.' David's inability to build — not for lack of desire but because the time was not right — is the OT analog of Christ's words that 'the time is not yet' (John 7:6, 8). The temple project requires rest from enemies as its prerequisite. The NT's temple — Christ's body, the church — is built in the eschatological peace secured by Christ's defeat of the powers (Col 2:15; Eph 2:14-16).</p>",
    "4": "<p>A shadow: 'But now the LORD my God has given me rest on every side. There is no enemy or threat of disaster.' The Solomonic rest is the OT's fullest realization of the land-rest promised in Deuteronomy (Deut 12:9-10). The author of Hebrews uses this rest language to point beyond Solomonic history to the eschatological rest that 'remains for the people of God' (Heb 4:9): 'For if Joshua had given them rest, God would not have spoken of another day later on' (Heb 4:8). Solomon's rest is real but partial — a chapter, not the conclusion, in the narrative of God's rest with his people.</p>",
    "5": "<p>A type: 'I therefore intend to build a house for the name of the LORD my God, as the LORD told my father David: Your son, whom I will set on your throne in your place, shall build the house for my name.' The Nathan oracle (2 Sam 7:12-13) promised that David's son would build the temple — a promise that has an immediate fulfillment (Solomon builds the stone temple) and an ultimate fulfillment (Christ is the true temple). John 2:19-21 makes the identification explicit: when Jesus says 'destroy this temple, and in three days I will raise it up,' John explains 'he was speaking about the temple of his body.' Solomon builds the type; Christ is the antitype.</p>",
    "6": "<p>A theme: Solomon requests cedars of Lebanon from Hiram, and proposes that Israelite workers will work alongside Hiram's servants. The collaboration of Israel and Gentile Tyre in building the temple is a shadow of the church — Jew and Gentile working together to build up the body of Christ. Paul's language in Ephesians 2:19-22 is explicitly temple-building language: the church, built on the foundation of apostles and prophets, with Christ as the cornerstone, grows 'into a holy temple in the Lord.'</p>",
    "7": "<p>A revelation of God: Hiram's response — 'Blessed be the LORD today, who has given David a wise son to rule over this great people' — is the blessing of YHWH by a Gentile king. This is the Abrahamic promise in miniature: 'through you all the families of the earth shall be blessed' (Gen 12:3), and Gentiles will bless YHWH. The NT completion is the universal praise of God among the nations (Rom 15:9-11; Rev 5:13): every tongue confessing that Jesus Christ is Lord to the glory of God the Father (Phil 2:11).</p>",
    "8": "<p>A theme: Hiram's agreement to supply cedar and cypress timber in exchange for Solomon's payment. The economic exchange — Israel's agricultural produce for Lebanon's timber — is the practical machinery of God's purpose to have his temple built. Providence works through ordinary commerce and international relations. The NT makes the same point about the church's mission: God works through tent-makers (Acts 18:3) and financial supporters (Phil 4:15-16) to advance the construction of the living temple.</p>",
    "9": "<p>A theme: the logistics of timber — floated down by sea, then handed off to Solomon's workers — demonstrate that the temple's construction requires careful coordination across great distances. The church's construction is similarly a multi-party, multi-location project: apostles lay foundations in one city, workers water what others plant (1 Cor 3:6), and the Spirit coordinates the whole. The Solomonic logistics are a shadow of the Spirit's coordination of the worldwide building project of the body of Christ.</p>",
    "10": "<p>A theme: 'So Hiram supplied Solomon with all the cedar and cypress timber he wanted.' Complete provision from a Gentile source for the holy project. The theme of sufficiency — YHWH ensuring that all necessary materials come together for the temple's completion — anticipates the NT's confidence that God who began the good work will bring it to completion (Phil 1:6). The temple project never lacks cedar; the church's building project will not lack what the Spirit supplies.</p>",
    "11": "<p>A theme: Solomon's payment to Hiram — twenty thousand cors of wheat and twenty thousand cors of pure olive oil — is a massive annual provision. The covenant exchange between Solomon and Hiram (grain and oil for timber) mirrors the covenant exchange in the gospel: what Israel has (the oracles of God, the covenant promises, the Messiah) goes out to the Gentiles; what the Gentiles bring (the fullness of the nations, the riches of the nations) comes in. Paul describes this exchange in Romans 15:27: 'if the Gentiles have come to share in their spiritual blessings, they ought also to be of service to them in material blessings.'</p>",
    "12": "<p>A revelation of God: 'The LORD gave Solomon wisdom as he had promised. There was peace between Hiram and Solomon, and the two of them made a treaty.' YHWH's faithfulness to his promise and the resulting peace between Israel and Tyre is the pattern that the NT presents as the gospel's outcome: the peace that Christ makes between Jew and Gentile through his cross (Eph 2:14-16). Solomon's covenant-peace with Hiram is the OT form; Christ's atonement is the cosmic content.</p>",
    "13": "<p>A shadow: 'King Solomon conscripted forced labor from all Israel — thirty thousand men in all.' The shadow side of Solomon's magnificent achievement is the conscription of forced labor. This is the beginning of the burden that will fracture the kingdom (1 Kgs 12:4). Christ's 'conscription' of disciples is radically different: 'Come to me, all who labor and are heavy laden, and I will give you rest. Take my yoke upon you and learn from me, for I am gentle and lowly in heart, and you will find rest for your souls. For my yoke is easy, and my burden is light' (Matt 11:28-30). The greater Son of David replaces conscription with invitation, coercion with rest.</p>",
    "14": "<p>A theme: the rotation of workers — one month in Lebanon, two months at home — suggests a system designed to prevent the permanent displacement of workers from their families and farms. Even within the conscription system, there is a pastoral concern for the workers' welfare. The NT's leadership principle similarly involves care for those who serve: elders are to tend the flock 'not domineering over those in your charge, but being examples to the flock' (1 Pet 5:3).</p>",
    "15": "<p>A theme: seventy thousand carriers and eighty thousand stonecutters in the hill country — the scale of human labor required to build the temple is immense. The temple is built at great human cost. The NT's temple — the church — is built at even greater cost: 'Christ loved the church and gave himself up for her' (Eph 5:25). The massive labor investment in Solomon's temple is a shadow of the infinite cost of the living temple, purchased not with human labor but with the blood of the Son (Acts 20:28).</p>",
    "16": "<p>A theme: three thousand three hundred supervisors who oversaw the workers — the managerial layer of the Solomonic building project. The church similarly has a structure of oversight: 'God has appointed in the church first apostles, second prophets, third teachers...' (1 Cor 12:28). The Solomonic administrative hierarchy for temple construction is the OT shadow of the spiritual gifts and offices through which the Spirit builds the living temple.</p>",
    "17": "<p>A shadow: 'At the king's command, they quarried large, expensive stones to lay the foundation of the house with cut stone.' The foundation of the Solomonic temple was laid with enormous, precisely cut stones — the costly, careful work of preparation before the visible structure could rise. The NT's temple-building language is consistent: 'no one can lay a foundation other than that which is laid, which is Jesus Christ' (1 Cor 3:11); the apostles and prophets are 'the foundation' with Christ as the cornerstone (Eph 2:20). Solomon's cut-stone foundation is the shadow; Christ as foundation is the reality.</p>",
    "18": "<p>A shadow: 'Solomon's builders, Hiram's builders, and the men of Gebal cut and prepared the timber and stone for the building of the house.' The temple's construction required the coordinated labor of Israelites and Gentiles working together. This inter-ethnic building project is the OT's most concrete image of what Paul describes in Ephesians 2:11-22: the wall between Jew and Gentile broken down in Christ, 'built together into a dwelling place for God by the Spirit.' Solomon's temple was built by Jews and Gentiles for a stone house; Christ's temple is built by Jews and Gentiles (and every nation) for the living dwelling of God in the Spirit.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', '1kings')
    merge_comm(existing, KINGS1)
    save_comm('mkt-christ', '1kings', existing)
    print('1 Kings 3–5 mkt-christ written.')

if __name__ == '__main__':
    main()
